.nav-lists-dropdown .nav-dropdown{display:none;position:absolute;top:100%;right:0;left:auto;margin-top:0;padding:.5rem 0;min-width:10rem;background:var(--paper);border:1px solid var(--line);box-shadow:0 .25rem 1rem rgba(0,0,0,.08);list-style:none}
.nav-lists-dropdown:hover .nav-dropdown,.nav-lists-dropdown.nav-dropdown-open .nav-dropdown{display:block}
.nav-dropdown{position:absolute;top:100%;left:0;margin:0;padding:.5rem 0;min-width:10rem;background:var(--paper);border:1px solid var(--line);box-shadow:0 .25rem 1rem rgba(0,0,0,.08);list-style:none}
.nav-dropdown a{display:block;padding:.4rem 1rem;white-space:nowrap;border:none;border-radius:0;background:none;color:var(--warm)}
.nav-dropdown a:hover{color:var(--warm);background:var(--line)}
.nav-hamburger-btn{display:none;background:none;border:none;color:var(--dim);cursor:pointer;font-size:1.7rem;line-height:1;padding:0;font-family:inherit}
.nav-hamburger-btn:hover{color:var(--warm)}
.nav-hamburger-panel{display:none;position:fixed;inset:0;z-index:1500;align-items:flex-start;justify-content:center;padding:3rem 1.5rem;pointer-events:none}
.nav-hamburger-panel[style*="flex"]{pointer-events:auto}
.nav-hamburger-overlay{position:fixed;inset:0;background:rgba(0,0,0,.3);cursor:pointer}
.nav-hamburger-inner{position:relative;z-index:2;background:var(--paper);border:1px solid var(--line);box-shadow:0 1rem 3rem rgba(0,0,0,.18),0 0 0 1px rgba(0,0,0,.06);max-width:20rem;width:100%;max-height:min(70vh,400px);overflow-y:auto;pointer-events:auto}
.nav-hamburger-list{list-style:none;padding:0;margin:0}
